// Define a sealed trait with allowed message types - only known types can be deserialized
sealed trait SafeMessage extends Serializable
final case class TextMessage(sender: String, content: String) extends SafeMessage
final case class PingMessage(timestamp: Long) extends SafeMessage
final case class PongMessage(timestamp: Long) extends SafeMessage

// Allowlist of classes that are permitted for deserialization
object MessageAllowlist {
  val allowedClasses: Set[String] = Set(
