// Safe deserialization using Akka's built-in serialization (NOT raw ObjectInputStream)
object SafeSerializer {
  def serialize(system: ActorSystem, message: AnyRef): Array[Byte] = {
    val serialization = akka.serialization.SerializationExtension(system)
    val serializer = serialization.findSerializerFor(message)
    serializer.toBinary(message)
  }

  def deserialize(system: ActorSystem, bytes: Array[Byte], clazz: Class[_]): Try[AnyRef] = {
    // Validate against allowlist BEFORE deserializing
    if (!MessageAllowlist.allowedClasses.contains(clazz.getName)) {
      scala.util.Failure(new SecurityException(
        s"Deserialization of class ${clazz.getName} is not allowed. " +
          s"Only allowlisted message types are permitted."
      ))
    } else {
      val serialization = akka.serialization.SerializationExtension(system)
      val serializer = serialization.findSerializerFor(clazz.getDeclaredConstructor().newInstance())
      Try(serializer.fromBinary(bytes, Some(clazz)).asInstanceOf[AnyRef])
    }
  }
}

// Message handler actor
class MessageHandlerActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case msg: TextMessage =>
      log.info(s"Received text from ${msg.sender}: ${msg.content}")
      // Validate and sanitize content
      val sanitized = msg.content.take(1000) // Limit content length
      log.info(s"Processing sanitized message: $sanitized")

    case msg: PingMessage =>
      log.info(s"Received ping at ${msg.timestamp}")
      sender() ! PongMessage(System.currentTimeMillis())

    case msg: PongMessage =>
      log.info(s"Received pong at ${msg.timestamp}")

    case unknown =>
      log.warning(s"Received unknown message type: ${unknown.getClass.getName}. Dropping.")
  }
}

// Network listener that receives messages safely
class NetworkListenerActor(port: Int) extends Actor with ActorLogging {
  private val handler = context.actorOf(Props[MessageHandlerActor](), "message-handler")
  private var serverSocket: ServerSocket = _
  private var running = true

  override def preStart(): Unit = {
    log.info(s"Starting secure network listener on port $port")
    serverSocket = new ServerSocket(port)

    // Run accept loop in a separate thread
    new Thread(() => acceptLoop()).start()
  }

  override def postStop(): Unit = {
    running = false
    if (serverSocket != null && !serverSocket.isClosed) {
      serverSocket.close()
    }
  }

  private def acceptLoop(): Unit = {
    while (running) {
      Try {
        val clientSocket = serverSocket.accept()
        log.info(s"Accepted connection from ${clientSocket.getRemoteSocketAddress}")
        handleClient(clientSocket)
      }.recover {
        case _: java.net.SocketException if !running => // Expected on shutdown
        case e: Exception => log.error(e, "Error accepting connection")
      }
    }
  }

  private def handleClient(socket: Socket): Unit = {
    Using.Manager { use =>
      val dis = use(new DataInputStream(socket.getInputStream))

      // Read class name and validate against allowlist FIRST
      val className = dis.readUTF()

      if (!MessageAllowlist.allowedClasses.contains(className)) {
        log.warning(s"Rejected disallowed class: $className from ${socket.getRemoteSocketAddress}")
        return
      }

      // Read payload length with size limit to prevent DoS
      val length = dis.readInt()
      val maxPayloadSize = 65536 // 64KB max
      if (length <= 0 || length > maxPayloadSize) {
        log.warning(s"Rejected payload with invalid size: $length from ${socket.getRemoteSocketAddress}")
        return
      }

      // Read serialized bytes
      val bytes = new Array[Byte](length)
      dis.readFully(bytes)

      // Deserialize safely using Akka serialization with allowlist check
      val clazz = Class.forName(className)
      SafeSerializer.deserialize(context.system, bytes, clazz) match {
        case scala.util.Success(msg: SafeMessage) =>
          log.info(s"Successfully deserialized ${msg.getClass.getSimpleName}")
          handler ! msg
        case scala.util.Success(other) =>
          log.warning(s"Deserialized non-SafeMessage type: ${other.getClass.getName}. Dropping.")
        case scala.util.Failure(ex) =>
          log.error(ex, s"Failed to safely deserialize message of class $className")
      }
    }.recover {
      case e: Exception =>
        log.error(e, s"Error handling client ${socket.getRemoteSocketAddress}")
    }

    Try(socket.close())
  }

  override def receive: Receive = {
    case "status" =>
      sender() ! s"Listening on port $port, running=$running"
  }
}

// Secure client for sending messages
object SecureClient {
  def sendMessage(system: ActorSystem, host: String, port: Int, message: SafeMessage): Try[Unit] = {
    Using.Manager { use =>
      val socket = use(new Socket(host, port))
      socket.setSoTimeout(5000)

      val dos = use(new DataOutputStream(socket.getOutputStream))
      val bytes = SafeSerializer.serialize(system, message)

      // Send class name for allowlist verification on receiver side
      dos.writeUTF(message.getClass.getName)
      dos.writeInt(bytes.length)
      dos.write(bytes)
      dos.flush()
    }
  }
}

